#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
char buf[1<<23],*p1=buf,*p2=buf;
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<21,stdin),p1==p2)?EOF:*p1++)
//#define DEBUG
//#define ONLINE
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &x){if(x>9)print(x/10);putchar(x%10+'0');}
const int N=2e5+10,M=5e5+10;
int head[N<<1],des[N<<1],nxt[N<<1],cgt,loc[N];struct ED{int u,v,w;}b[M];
inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
int w[N<<1],n,cmt,m,fa[18][N<<1],Lg[N<<1],P[N],p,dep[N<<1],RT[N],ql[N<<1],qr[N<<1],cdt,Q,a[N];
inline int bnd(int k){int l=1,r=p,m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int FA[N];inline int fnd(int x){return FA[x]==x?x:FA[x]=fnd(FA[x]);}

struct Seg{int l,r,sz;}t[N*18];int Rt[N],cnt;
inline void update(int x){t[x].sz=t[t[x].l].sz+t[t[x].r].sz;}
inline void add(int cur,int &x,int pos,int l=1,int r=p)
{
	t[x=++cnt]=t[cur];if(l==r){++t[x].sz;return;} int mid=(l+r)>>1;
	pos<=mid?add(t[cur].l,t[x].l,pos,l,mid):add(t[cur].r,t[x].r,pos,mid+1,r);update(x);
}
inline int qry(int rr,int rl,int k,int l=1,int r=p)
{
	if(l==r)return P[l];int rsz=t[t[rr].r].sz-t[t[rl].r].sz,mid=(l+r)>>1;
	return rsz>=k?qry(t[rr].r,t[rl].r,k,mid+1,r):qry(t[rr].l,t[rl].l,k-rsz,l,mid);
}
inline void dfs(int u)
{
	rep(1,Lg[dep[u]],i)fa[i][u]=fa[i-1][fa[i-1][u]];
	if(!head[u]){loc[ql[u]=qr[u]=++cdt]=u;return;}
	for(int i=head[u];i;i=nxt[i])
	{
		int v=des[i];dep[v]=dep[u]+1;
		dfs(v);if(!ql[u])ql[u]=ql[v];qr[u]=qr[v];
	}
}
int main()
{
	cmt=n=read();m=read();Q=read();rep(1,n,i)P[i]=a[FA[i]=i]=read(),RT[i]=i;
	std::sort(P+1,P+n+1);p=n;rep(1,n,i)a[i]=bnd(a[i]);
	Lg[0]=-1;rep(1,n<<1,i)Lg[i]=Lg[i>>1]+1;
	rep(1,m,i)b[i].u=read(),b[i].v=read(),b[i].w=read();
	std::sort(b+1,b+m+1,[&](const ED&x,const ED&y){return x.w<y.w;});
	rep(1,m,i)
	{
		int U=fnd(b[i].u),V=fnd(b[i].v);if(U==V)continue;
		ins(++cmt,RT[V]);ins(cmt,RT[U]);
		w[fa[0][RT[U]]=fa[0][RT[V]]=cmt]=b[i].w;RT[FA[U]=V]=cmt;
	}
	rep(1,n,i)if(FA[i]==i)dfs(RT[i]);rep(1,n,i)add(Rt[i-1],Rt[i],a[loc[i]]);w[0]=0x7fffffff;
	int lst=0;while(Q--)
	{
		int s=(read()^lst)%n+1,x=read()^lst,k=(read()^lst)%n+1;
		int u=s;drep(Lg[dep[u]],0,i)if(w[fa[i][u]]<=x)u=fa[i][u];
		if(qr[u]-ql[u]+1<k){puts("-1");lst=0;continue;}
		print(lst=qry(Rt[qr[u]],Rt[ql[u]-1],k));putchar('\n');
	}
}
